from flask import Flask, request, jsonify
from bson.json_util import dumps
import pymongo

app = Flask(__name__)

# Connect to MongoDB at localhost:27017
client = pymongo.MongoClient("mongodb://localhost:27017/")
db = client["mydatabase"]
collection = db["users"]

# User profile storage
@app.route("/users", methods=["POST"])
def create_user():
    data = request.get_json()
    user = {"username": data["username"], "email": data["email"]}
    collection.insert_one(user)
    return jsonify({"message": "User created successfully"}), 201

@app.route("/users/<username>", methods=["GET"])
def get_user(username):
    user = collection.find_one({"username": username})
    if user:
        return jsonify(user)
    else:
        return jsonify({"message": "User not found"}), 404

@app.route("/users/<username>", methods=["PUT"])
def update_user(username):
    data = request.get_json()
    user = {"username": username, "email": data["email"]}
    collection.update_one({"username": username}, {"$set": user})
    return jsonify({"message": "User updated successfully"}), 200

@app.route("/users/<username>", methods=["DELETE"])
def delete_user(username):
    collection.delete_one({"username": username})
    return jsonify({"message": "User deleted successfully"}), 200

# Document queries
@app.route("/documents", methods=["GET"])
def get_documents():
    documents = list(collection.find())
    return dumps(documents)

@app.route("/documents/<id>", methods=["GET"])
def get_document(id):
    document = collection.find_one({"_id": ObjectId(id)})
    if document:
        return jsonify(document)
    else:
        return jsonify({"message": "Document not found"}), 404

# Aggregation pipelines
@app.route("/aggregate", methods=["POST"])
def aggregate():
    data = request.get_json()
    pipeline = [{"$match": {"username": data["username"]}}, {"$sort": {"createdAt": -1}}]
    documents = list(collection.aggregate(pipeline))
    return dumps(documents)